import { requestJSON } from "@/lib/http";

export type AuthUser = {
  id: string;
  email: string;
  role: string;
  display_name: string | null;
};

export type AuthResponse = {
  token: string;
  user: AuthUser;
};

export type SellerStore = {
  id: string;
  name: string;
  description: string | null;
  phone: string | null;
  image_url?: string | null;
  is_active: boolean;
  created_at: string;
  updated_at: string;
};

export type SellerPickupLocation = {
  id: string;
  label: string | null;
  address1: string;
  address2: string | null;
  city: string;
  region: string;
  postal_code: string;
  country: string;
  timezone: string;
  photo_url?: string | null;
};

export type SellerPickupWindow = {
  id: string;
  start_at: string;
  end_at: string;
  cutoff_at: string;
  status: string;
  notes: string | null;
  pickup_location: SellerPickupLocation;
  created_at: string;
  updated_at: string;
};

export type SellerSubscriptionPlan = {
  id: string;
  store_id: string;
  pickup_location_id: string;
  product_id: string;
  title: string;
  description: string | null;
  image_url?: string | null;
  cadence: string;
  price_cents: number;
  subscriber_limit: number;
  first_start_at: string;
  duration_minutes: number;
  cutoff_hours: number;
  is_active: boolean;
  is_live: boolean;
  deposit_cents: number;
  created_at: string;
  updated_at: string;
  next_start_at: string;
  pickup_location: SellerPickupLocation;
};

export type SellerProduct = {
  id: string;
  title: string;
  description: string | null;
  unit: string;
  is_perishable: boolean;
  is_active: boolean;
};

export type SellerOffering = {
  id: string;
  pickup_window_id: string;
  product_id: string;
  price_cents: number;
  quantity_available: number;
  quantity_reserved: number;
  status: string;
  product: SellerProduct;
};

export type SellerOrderItem = {
  id: string;
  offering_id: string | null;
  product_title: string;
  product_unit: string;
  price_cents: number;
  quantity: number;
  line_total_cents: number;
};

export type SellerOrder = {
  id: string;
  store_id: string;
  pickup_window_id: string;
  buyer_email: string;
  buyer_name: string | null;
  buyer_phone: string | null;
  status: string;
  payment_method: string;
  payment_status: string;
  subtotal_cents: number;
  buyer_fee_cents: number;
  total_cents: number;
  captured_cents: number;
  created_at: string;
  items: SellerOrderItem[];
};

export type SellerPayoutSummary = {
  store_id: string;
  pickup_window_id: string;
  seller_payout_cents: number;
  platform_fee_cents: number;
  gross_captured_cents: number;
  picked_up_count: number;
  no_show_count: number;
  canceled_count: number;
  open_count: number;
  payout_picked_up_cents: number;
  payout_no_show_cents: number;
};

export type PlacesAutocompletePrediction = {
  place_id: string;
  main_text: string;
  secondary_text: string;
  full_text: string;
};

export type PlacesAutocompleteResponse = {
  predictions: PlacesAutocompletePrediction[];
};

export type PlacesDetailsResponse = {
  address1: string;
  city: string;
  region: string;
  postal_code: string;
  country: string;
  formatted_address: string;
  lat: number | null;
  lng: number | null;
};

export type TimezoneResponse = {
  time_zone_id: string;
};

export type PickupPreviewResponse = {
  order_id: string;
  store_id: string;
  store_name: string;
  status: string;
  buyer_name: string | null;
  buyer_email: string;
  items: SellerOrderItem[];
  subtotal_cents: number;
  buyer_fee_cents: number;
  total_cents: number;
  payment_status: string;
  pickup_window_id: string;
  created_at: string;
  updated_at: string;
};

export type PickupConfirmResponse = {
  order_id: string;
  store_id: string;
  pickup_window_id: string;
  status: string;
  buyer_name: string | null;
  buyer_email: string;
  items: SellerOrderItem[];
  total_cents: number;
  subtotal_cents: number;
  confirmed_at: string;
};

